mapper.select:
SELECT CODE, DTL_CODE, RTRIM(DTL_CODE_NM) AS DTL_CODE_NM, DATE_FORMAT(START_DATE, '%Y-%m-%d') AS START_DATE , DATE_FORMAT(END_DATE, '%Y-%m-%d') AS END_DATE , USE_YN, IFNULL(SORT,'-') AS SORT FROM T_COMM_MST_DTL WHERE CODE = #{code}
AND ( DTL_CODE LIKE CONCAT('%',#{dtlCode},'%') )
ORDER BY CODE ,DTL_CODE

SELECT 'Y'
  FROM T_COMM_MST_DTL
 WHERE CODE      = #{code}
   AND DTL_CODE  = #{dtlCode}
